    @Test
    fun `fetchWeatherForPort returns NoCoordinates when port has no lat-lon`() = runTest {
        val portWithoutCoords = testPort.copy(latitude = null, longitude = null)
        val result = repository.fetchWeatherForPort(portWithoutCoords)
        assertThat(result).isEqualTo(WeatherFetchResult.NoCoordinates)
        coVerify(exactly = 0) { api.fetchHistoricalWeather(any(), any(), any(), any()) }
    }

    @Test
    fun `fetchWeatherForPort returns Failure when all year fetches fail`() = runTest {
        coEvery { api.fetchHistoricalWeather(any(), any(), any(), any()) } throws RuntimeException("network error")
