    @Test
    fun `isFetchNeeded returns true when no summary exists`() = runTest {
        coEvery { weatherDao.getSummaryForPortOnce(1L) } returns null
        assertThat(repository.isFetchNeeded(1L)).isTrue()
    }

    @Test
    fun `isFetchNeeded returns false when summary is fresh`() = runTest {
        val freshSummary = buildSummary(fetchedAt = Instant.now())
        coEvery { weatherDao.getSummaryForPortOnce(1L) } returns freshSummary
        assertThat(repository.isFetchNeeded(1L)).isFalse()
    }

    @Test
    fun `isFetchNeeded returns true when summary is stale`() = runTest {
        val staleSummary = buildSummary(
            fetchedAt = Instant.now().minusSeconds(8L * 24 * 3600), // 8 days ago
        )
        coEvery { weatherDao.getSummaryForPortOnce(1L) } returns staleSummary
        assertThat(repository.isFetchNeeded(1L)).isTrue()
    }

    @Test
    fun `computeSummary rain probability counts years above 1mm threshold`() = runTest {
        // 3 rainy, 2 dry — expect rainyYearCount = 3
        val fakeDaily = DailyWeatherData(
            time = listOf("2025-12-16"),
            tempMaxF = listOf(80.0),
            tempMinF = listOf(70.0),
            precipMm = listOf(0.0), // Will be overridden in the loop
            precipHours = listOf(0.0),
            windMaxMph = listOf(10.0),
            windGustMph = listOf(15.0),
            humidityPct = listOf(70.0),
            uvIndexMax = listOf(8.0),
            sunshineDurationSec = listOf(20000.0),
        )
        val rainyResponse = HistoricalWeatherResponse(
            latitude = 20.43,
            longitude = -86.92,
            daily = fakeDaily.copy(precipMm = listOf(5.0)),
        )
        val dryResponse = HistoricalWeatherResponse(
            latitude = 20.43,
            longitude = -86.92,
            daily = fakeDaily.copy(precipMm = listOf(0.0)),
        )

        var callCount = 0
        coEvery { api.fetchHistoricalWeather(any(), any(), any(), any()) } answers {
            callCount++
            // years: 2025, 2024, 2023 = rainy; 2022, 2021 = dry
            if (callCount <= 3) rainyResponse else dryResponse
        }
        coEvery { weatherDao.getSummaryForPortOnce(any()) } returns null

        repository.fetchWeatherForPort(testPort)

        coVerify {
            weatherDao.insertSummary(
                match { summary ->
                    summary.rainyYearCount == 3 && summary.totalYearCount == 5
                },
            )
        }
    }

    @Test
